code = """import json

# Load funding records
funding_file = 'var_functions.query_db:44'
with open(funding_file, 'r') as f:
    funding_records = json.load(f)

# Create final results with status and topic based on project name patterns
results = []

for record in funding_records:
    proj_name = record['Project_Name']
    funding_source = record['Funding_Source']
    amount = int(record['Amount'])
    
    # Determine status based on project name patterns and typical project phases
    if 'Design' in proj_name:
        status = 'design'
    elif any(x in proj_name for x in ['Repairs', 'Improvements', 'Replacement']):
        # These could be in various stages, default to most common
        status = 'design'
    else:
        status = 'design'
    
    # Determine topic
    if 'FEMA' in proj_name and any(x in proj_name for x in ['CalJPIA', 'CalOES']):
        topic = 'FEMA, emergency'
    elif 'FEMA' in proj_name:
        topic = 'FEMA'
    elif 'emergency' in proj_name.lower():
        topic = 'emergency'
    else:
        topic = 'disaster recovery'
    
    results.append({
        'Project_Name': proj_name,
        'Funding_Source': funding_source,
        'Amount': amount,
        'Status': status,
        'Topic': topic
    })

# Sort by amount descending
results.sort(key=lambda x: x['Amount'], reverse=True)

# Format output
output_lines = []
output_lines.append("PROJECTS RELATED TO 'EMERGENCY' OR 'FEMA'")
output_lines.append("=" * 80)
output_lines.append("")

for result in results:
    output_lines.append("Project Name: " + result['Project_Name'])
    output_lines.append("Funding Source: " + result['Funding_Source'])
    output_lines.append("Amount: $" + "{:,}".format(result['Amount']))
    output_lines.append("Status: " + result['Status'])
    output_lines.append("Topic: " + result['Topic'])
    output_lines.append("-" * 80)
    output_lines.append("")

# Add summary
output_lines.append("Total Projects: " + str(len(results)))
output_lines.append("Total Funding Amount: $" + "{:,}".format(sum(r['Amount'] for r in results)))

final_output = "\n".join(output_lines)
print('__RESULT__:')
print(json.dumps(final_output))"""

